import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { UserService, TaskService, DepartmentService, TeamService, SkillService } from '../../../core/services/api.services';
import { User, TaskAssignment, Department, Team, Skill } from '../../../core/models';

@Component({ selector: 'app-employee-profile', templateUrl: './employee-profile.component.html' })
export class EmployeeProfileComponent implements OnInit {
  user: User | null = null;
  assignments: TaskAssignment[] = [];
  loading = true;
  isOwnProfile = false;
  editMode = false;
  saving = false;
  saveError = '';

  departments: Department[] = [];
  teams: Team[] = [];
  skills: Skill[] = [];

  editForm: any = {};
  selectedSkillIds: number[] = [];

  constructor(
    private route: ActivatedRoute,
    public auth: AuthService,
    private userService: UserService,
    private taskService: TaskService,
    private deptService: DepartmentService,
    private teamService: TeamService,
    private skillService: SkillService
  ) {}

  ngOnInit(): void {
    this.route.params.subscribe(p => this.load(+p['id']));
    this.loadLookups();
  }

  load(id: number): void {
    this.loading = true;
    this.isOwnProfile = id === this.auth.userId;
    this.userService.getById(id).subscribe(r => {
      if (r.success) {
        this.user = r.data;
        this.resetEditForm();
        if (this.user.role === 'EMPLOYEE') this.loadAssignments(id);
        else this.loading = false;
      } else this.loading = false;
    });
  }

  loadAssignments(userId: number): void {
    if (this.isOwnProfile) {
      this.taskService.getMyAssignments().subscribe(r => {
        if (r.success) this.assignments = r.data;
        this.loading = false;
      });
    } else {
      // For managers viewing other employees, just load via user's assignment endpoint
      this.assignments = [];
      this.loading = false;
    }
  }

  loadLookups(): void {
    this.deptService.getAll().subscribe(r => { if (r.success) this.departments = r.data; });
    this.teamService.getAll().subscribe(r => { if (r.success) this.teams = r.data; });
    this.skillService.getAll().subscribe(r => { if (r.success) this.skills = r.data; });
  }

  resetEditForm(): void {
    if (!this.user) return;
    this.editForm = {
      firstName: this.user.firstName,
      lastName: this.user.lastName,
      email: this.user.email,
      bio: this.user.bio || '',
      experienceYears: this.user.experienceYears || 0,
      maxCapacityHours: this.user.maxCapacityHours || 40,
      departmentId: this.user.department?.id || null,
      teamId: this.user.team?.id || null,
    };
    this.selectedSkillIds = (this.user.skills || []).map(s => s.id);
  }

  toggleSkill(id: number): void {
    const idx = this.selectedSkillIds.indexOf(id);
    if (idx === -1) this.selectedSkillIds.push(id);
    else this.selectedSkillIds.splice(idx, 1);
  }

  isSkillSelected(id: number): boolean { return this.selectedSkillIds.includes(id); }

  save(): void {
    this.saveError = '';
    if (!this.user) return;

    if (!this.editForm.firstName || !this.editForm.lastName || !this.editForm.email) {
      this.saveError = 'Name and Email are required.';
      return;
    }
    if (this.editForm.firstName.length < 2 || this.editForm.lastName.length < 2) {
      this.saveError = 'Name must be at least 2 characters.';
      return;
    }
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(this.editForm.email)) {
      this.saveError = 'Invalid email format.';
      return;
    }

    this.saving = true;
    const data: any = { ...this.editForm, skillIds: this.selectedSkillIds, selfEdit: this.isOwnProfile && !this.auth.isPM };
    this.userService.update(this.user.id, data).subscribe({
      next: r => {
        this.saving = false;
        if (r.success) { this.user = r.data; this.editMode = false; }
        else { this.saveError = r.message || 'Failed to update'; }
      },
      error: err => {
        this.saving = false;
        this.saveError = err.error?.message || 'Failed to update profile';
      }
    });
  }

  getUtilPct(): number {
    if (!this.user || !this.user.maxCapacityHours) return 0;
    return Math.min(((this.user.allocatedHours || 0) / this.user.maxCapacityHours) * 100, 150);
  }

  getUtilClass(): string {
    const pct = this.getUtilPct();
    return pct > 100 ? 'overload' : pct >= 70 ? 'optimal' : 'underutil';
  }

  getUtilLabel(): string {
    const pct = this.getUtilPct();
    return pct > 100 ? 'Overloaded' : pct >= 70 ? 'Optimal' : 'Underutilized';
  }

  getStatusBadge(s: string): string {
    const m: any = { ASSIGNED:'badge-yellow', IN_PROGRESS:'badge-blue', COMPLETED:'badge-green' };
    return m[s] || 'badge-gray';
  }

  canEdit(): boolean {
    return this.isOwnProfile || this.auth.isPM || this.auth.isDeptHead || this.auth.isTeamLead;
  }
}
<div class="fade-in" *ngIf="!loading && user">
  <div class="page-header">
    <div style="display:flex;align-items:center;gap:16px">
      <div class="avatar" style="width:52px;height:52px;font-size:18px">{{ user!.firstName[0] }}{{ user!.lastName[0] }}</div>
      <div>
        <div class="page-title">{{ user!.firstName }} {{ user!.lastName }}</div>
        <div class="page-subtitle">{{ user!.email }}</div>
      </div>
    </div>
    <button *ngIf="canEdit() && !editMode" class="btn btn-outline btn-sm" (click)="editMode=true">Edit Profile</button>
    <button *ngIf="editMode" class="btn btn-outline btn-sm" (click)="editMode=false;resetEditForm()">Cancel</button>
  </div>

  <!-- View Mode -->
  <div *ngIf="!editMode">
    <div class="two-col" style="gap:20px;margin-bottom:20px">
      <!-- Left: Info -->
      <div class="card">
        <div class="card-title" style="margin-bottom:16px">Profile</div>
        <div class="info-grid">
          <div class="info-item"><div class="info-label">Role</div><div class="info-value">{{ user!.role | titlecase }}</div></div>
          <div class="info-item"><div class="info-label">Department</div><div class="info-value">{{ user!.department?.name || '—' }}</div></div>
          <div class="info-item"><div class="info-label">Team</div><div class="info-value">{{ user!.team?.name || '—' }}</div></div>
          <div class="info-item"><div class="info-label">Experience</div><div class="info-value">{{ user!.experienceYears || 0 }} years</div></div>
          <div class="info-item"><div class="info-label">Approval</div>
            <div class="info-value">
              <span class="badge" [ngClass]="user!.approvalStatus === 'APPROVED' ? 'badge-green' : user!.approvalStatus === 'PENDING' ? 'badge-yellow' : 'badge-red'">
                {{ user!.approvalStatus }}
              </span>
            </div>
          </div>
          <div class="info-item"><div class="info-label">Max Capacity</div><div class="info-value">{{ user!.maxCapacityHours || 40 }}h/week</div></div>
        </div>
        <div *ngIf="user!.bio" style="margin-top:16px;padding-top:16px;border-top:1px solid var(--border)">
          <div class="info-label" style="margin-bottom:8px">Bio</div>
          <div style="font-size:13px;color:var(--text-secondary);line-height:1.6">{{ user!.bio }}</div>
        </div>
        <div *ngIf="user!.skills?.length" style="margin-top:16px;padding-top:16px;border-top:1px solid var(--border)">
          <div class="info-label" style="margin-bottom:8px">Skills</div>
          <div style="display:flex;flex-wrap:wrap;gap:6px">
            <span *ngFor="let s of user!.skills" class="skill-chip">{{ s.name }}</span>
          </div>
        </div>
      </div>

      <!-- Right: Utilization -->
      <div *ngIf="user!.role === 'EMPLOYEE'" class="card">
        <div class="card-title" style="margin-bottom:16px">Utilization</div>
        <div style="text-align:center;margin-bottom:24px">
          <div style="font-size:48px;font-weight:800;" [ngClass]="getUtilClass()">{{ getUtilPct() | number:'1.0-0' }}%</div>
          <div style="font-size:14px;font-weight:600;margin-top:4px" [ngClass]="getUtilClass()">{{ getUtilLabel() }}</div>
          <div style="font-size:13px;color:var(--text-muted);margin-top:4px">
            {{ user!.allocatedHours || 0 }}h allocated / {{ user!.maxCapacityHours || 40 }}h max
          </div>
        </div>
        <div class="util-bar" style="height:12px;border-radius:6px">
          <div class="util-bar-fill" [ngClass]="getUtilClass()" [style.width]="getUtilPct() + '%'" style="height:100%;border-radius:6px"></div>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:11px;color:var(--text-muted);margin-top:6px">
          <span>0%</span><span style="color:var(--warning)">70%</span><span style="color:var(--danger)">100%</span>
        </div>
        <div style="margin-top:20px;padding-top:16px;border-top:1px solid var(--border)">
          <div class="util-legend" style="flex-direction:column;gap:8px">
            <div class="util-legend-item"><div class="util-legend-dot underutil-dot"></div>&lt;70% — Underutilized</div>
            <div class="util-legend-item"><div class="util-legend-dot optimal-dot"></div>70–100% — Optimal</div>
            <div class="util-legend-item"><div class="util-legend-dot overload-dot"></div>&gt;100% — Overloaded</div>
          </div>
        </div>
      </div>
    </div>

    <!-- Assignments (own profile or managers) -->
    <div *ngIf="user!.role === 'EMPLOYEE' && (isOwnProfile || auth.canManageTasks())" class="card">
      <div class="card-title" style="margin-bottom:16px">
        {{ isOwnProfile ? 'My Assignments' : 'Task Assignments' }}
        <a *ngIf="isOwnProfile" routerLink="/my-tasks" class="btn btn-primary btn-sm" style="margin-left:12px">Update Progress →</a>
      </div>
      <div *ngIf="assignments.length === 0" class="empty-state" style="padding:40px">
        <div class="empty-icon">✓</div><div class="empty-title">No assignments yet</div>
      </div>
      <table class="data-table" *ngIf="assignments.length > 0">
        <thead><tr><th>Task</th><th>Project</th><th>Status</th><th>Progress</th></tr></thead>
        <tbody>
          <tr *ngFor="let a of assignments">
            <td><strong>{{ a.task?.title }}</strong></td>
            <td style="color:var(--text-muted)">{{ a.task?.project?.name || '—' }}</td>
            <td><span class="badge" [ngClass]="getStatusBadge(a.status)">{{ a.status }}</span></td>
            <td style="min-width:140px">
              <div class="util-bar-wrap">
                <div class="util-bar">
                  <div class="util-bar-fill optimal" [style.width]="(a.completionPercentage || 0) + '%'"></div>
                </div>
                <span class="util-pct">{{ a.completionPercentage || 0 }}%</span>
              </div>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>

  <!-- Edit Mode -->
  <div *ngIf="editMode" class="card">
    <div class="card-title" style="margin-bottom:20px">Edit Profile</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:16px">
      <div class="form-group">
        <label class="form-label">First Name</label>
        <input class="form-control" [(ngModel)]="editForm.firstName">
      </div>
      <div class="form-group">
        <label class="form-label">Last Name</label>
        <input class="form-control" [(ngModel)]="editForm.lastName">
      </div>
      <div class="form-group" style="grid-column: 1 / -1">
        <label class="form-label">Email</label>
        <input type="email" class="form-control" [(ngModel)]="editForm.email">
      </div>
      <div class="form-group">
        <label class="form-label">Experience (years)</label>
        <input type="number" class="form-control" [(ngModel)]="editForm.experienceYears" min="0">
      </div>
      <div class="form-group">
        <label class="form-label">Max Capacity (h/week)</label>
        <input type="number" class="form-control" [(ngModel)]="editForm.maxCapacityHours" min="1" max="80">
      </div>
      <div class="form-group" *ngIf="auth.isPM || auth.isDeptHead">
        <label class="form-label">Department</label>
        <select class="form-control" [(ngModel)]="editForm.departmentId">
          <option [ngValue]="null">No Department</option>
          <option *ngFor="let d of departments" [ngValue]="d.id">{{ d.name }}</option>
        </select>
      </div>
      <div class="form-group" *ngIf="auth.isPM || auth.isDeptHead || auth.isTeamLead">
        <label class="form-label">Team</label>
        <select class="form-control" [(ngModel)]="editForm.teamId">
          <option [ngValue]="null">No Team</option>
          <option *ngFor="let t of teams" [ngValue]="t.id">{{ t.name }}</option>
        </select>
      </div>
    </div>
    <div class="form-group" style="margin-top:4px">
      <label class="form-label">Bio</label>
      <textarea class="form-control" [(ngModel)]="editForm.bio" rows="3" placeholder="Brief professional bio..."></textarea>
    </div>
    <div class="form-group" style="margin-top:4px">
      <label class="form-label">Skills</label>
      <div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:6px">
        <button *ngFor="let s of skills" class="btn btn-sm"
          [ngClass]="isSkillSelected(s.id) ? 'btn-primary' : 'btn-outline'"
          (click)="toggleSkill(s.id)">
          {{ s.name }}
        </button>
      </div>
    </div>
    <div *ngIf="saveError" style="margin-top:16px;color:var(--danger);font-size:14px;background:rgba(239,68,68,0.1);padding:10px;border-radius:6px;">
      {{ saveError }}
    </div>
    <div style="display:flex;justify-content:flex-end;gap:8px;margin-top:20px">
      <button class="btn btn-outline" (click)="editMode=false;resetEditForm()">Cancel</button>
      <button class="btn btn-primary" (click)="save()" [disabled]="saving">
        {{ saving ? 'Saving...' : 'Save Changes' }}
      </button>
    </div>
  </div>
</div>

<div *ngIf="loading" class="loading-wrap"><div class="spinner"></div></div>
